#!/usr/bin/env node
/**
 * gen-zone-marker-glbs — author one symbolic GLB per Permaculture Zone (0-5).
 *
 * Phase 4 of ADR `2026-05-11-atlas-deckgl-scenegraph-migration.md`. Zone
 * markers are symbolic points — short coloured pillars whose colour encodes
 * the zone number (cool inner zones → warm outer zones). Each pillar is
 * topped with a small disc to read as "a zone post stuck in the ground."
 *
 * Output GLBs are CC0 — generated by code in this repo. See
 * `public/models/zone-markers/NOTICE.md`.
 *
 * Convention: unit-normalized so the base sits at Y=0 and the cap sits at
 * Y=1. The layer scales the model to footprintM × heightM × footprintM.
 *
 * Run via:    pnpm --filter @ogden/web gen:models
 */

import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';
import { writeGLB } from './lib/glb-writer.mjs';
import { cylinder, merge } from './lib/primitives.mjs';

const __dirname = dirname(fileURLToPath(import.meta.url));
const OUT_DIR = join(__dirname, '..', 'public', 'models', 'zone-markers');

/** Pillar with a wider cap disc at the top. */
function pillar() {
  return merge([
    cylinder(0.12, 0.85, 12, 0.0),
    cylinder(0.30, 0.15, 16, 0.85),
  ]);
}

// Zone palette — Permaculture convention: house (0) → wild (5).
// Cool blues for inner zones, warming to ochres and greens for outer wilds.
const KINDS = {
  'zone-0': { color: [0.85, 0.85, 0.85], build: pillar }, // House — neutral
  'zone-1': { color: [0.95, 0.78, 0.40], build: pillar }, // Kitchen garden — warm yellow
  'zone-2': { color: [0.65, 0.82, 0.45], build: pillar }, // Orchards / small livestock — light green
  'zone-3': { color: [0.45, 0.70, 0.40], build: pillar }, // Main crops / pasture — mid green
  'zone-4': { color: [0.35, 0.55, 0.30], build: pillar }, // Forage / woodlot — dark green
  'zone-5': { color: [0.25, 0.40, 0.25], build: pillar }, // Wild — deep forest
};

let totalBytes = 0;
let totalKinds = 0;
for (const [kind, spec] of Object.entries(KINDS)) {
  const mesh = spec.build();
  const outPath = join(OUT_DIR, `${kind}.glb`);
  const stats = writeGLB(
    {
      positions: mesh.positions,
      normals: mesh.normals,
      indices: mesh.indices,
      color: spec.color,
      name: kind,
    },
    outPath,
  );
  console.log(
    `wrote ${outPath} (${stats.bytes} bytes, ${stats.vertexCount} verts, ${stats.triangleCount} tris)`,
  );
  totalBytes += stats.bytes;
  totalKinds += 1;
}
console.log(`\n${totalKinds} zone-marker kinds, ${totalBytes} bytes total`);
